public static String getEmailTemplateIdList(String listTemplateNames) {
	List<String> idList = new List<String>();
	List<String> listNames = listTemplateNames.split(',');
	List<EmailTemplate> emailTemplate = [select Id from EmailTemplate where DeveloperName In :listNames];
	for (EmailTemplate temp : emailTemplate) {
		idList.add(temp.Id);
	}
	return idList.toString().substring(1, idList.toString().length() - 1).replace(' ','');
}

